const path = require('path');
const fs = require('fs-extra');
const { spawnSync } = require('child_process');

(async function () {
  const rootDir = path.resolve(__dirname, '../');
  const distDir = path.join(rootDir, 'dist');
  const zipPath = path.join(rootDir, 'dist.zip');

  // Copy the built popup/sidebar UI and the static service-worker shim.
  await fs.copy(
    path.resolve(rootDir, '../extension-ui/build'),
    distDir,
    {
      overwrite: true,
    }
  );
  await fs.copy(
    path.join(rootDir, 'service-worker.js'),
    path.join(distDir, 'service-worker.js')
  );

  // The webpack background build (run before this script) emits the entry
  // `background.js` plus several `bg-*.js` split chunks, each kept under AMO's
  // 5 MB per-file limit. Discover them and wire them into the manifest.
  const chunkFiles = (await fs.readdir(distDir))
    .filter((f) => /^bg-.*\.js$/.test(f))
    .sort();
  // Load order: every split chunk first, the entry (`background.js`) last so all
  // modules are registered before the entry runtime starts.
  const backgroundScripts = [...chunkFiles, 'background.js'];

  // Chrome service workers can't list multiple files, so generate a tiny loader
  // that importScripts() all of them (synchronous, allowed at SW top level).
  const swLoader =
    '// Auto-generated by scripts/bundle.js. Loads the split background bundle.\n' +
    `importScripts(${backgroundScripts.map((f) => `'${f}'`).join(', ')});\n`;
  await fs.writeFile(path.join(distDir, 'sw.js'), swLoader, 'utf8');

  // Build the distributable manifest: Firefox (event page) reads `scripts`,
  // Chrome (service worker) reads `service_worker`.
  const manifest = await fs.readJson(path.join(rootDir, 'manifest.json'));
  manifest.background = {
    scripts: backgroundScripts,
    service_worker: 'sw.js',
  };
  await fs.writeJson(path.join(distDir, 'manifest.json'), manifest, { spaces: 2 });

  await fs.writeFile(
    path.join(distDir, 'LOAD_HERE.txt'),
    [
      'Load this extension from THIS folder (dist), not the parent extension/ folder.',
      '',
      'Firefox:',
      '  about:debugging -> Load Temporary Add-on -> select manifest.json in THIS folder',
      '',
      'Chrome / Brave / Edge:',
      '  chrome://extensions -> Load unpacked -> select THIS dist folder',
      '',
    ].join('\n'),
    'utf8'
  );

  // Firefox/store zips need manifest.json at the archive root — not inside a
  // dist/ folder. `-C distDir .` packs the folder *contents*, and shell:false
  // avoids Windows arg-mangling that previously nested everything under dist/.
  await fs.remove(zipPath);
  const zipResult = spawnSync(
    'tar',
    ['-caf', zipPath, '-C', distDir, '.'],
    { stdio: 'inherit', shell: false }
  );
  if (zipResult.status !== 0) {
    console.warn('Could not create dist.zip (tar failed). Load manifest.json from dist/ instead.');
  } else {
    console.log(`Packaged extension zip to ${zipPath}`);
  }

  console.log(`Bundled extension to ${distDir} (${backgroundScripts.length} background scripts)`);
})();
